/**
 * @fileoverview PinInput component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, ARIA attrs, defaults
 *   state.js     — reactive state wiring + field sync effect
 *   view.js      — DOM setup / teardown
 *   events.js    — centralised event binding (AbortController cleanup)
 *
 * @module module/PinInput
 */

import { default as razyui } from '../../index.js';
import { StateMachine } from '../shared/StateMachine.js';
import { PinInputDef as DEF } from '../PinInput.def.js';

import { DEFAULTS, CLS }                   from './constants.js';
import { createReactiveState }             from './state.js';
import { buildDOM, cleanupDOM }            from './view.js';
import { createHandlerCtx, bindEvents }    from './events.js';
import { emitEvent }                       from '../shared/emitEvent.js';

/**
 * PinInput — v2 modular rewrite (JIT-compatible)
 *
 * PIN / OTP code input — a row of individual character fields that
 * auto-advance on entry, support paste, backspace navigation, and
 * masked (password) mode.
 *
 * Reactive state via razyui.state(); property setters on getControl().
 *
 * Features:
 *   - Configurable length (default 6)
 *   - Numeric-only or alphanumeric mode
 *   - Masked (password) display
 *   - Auto-focus next field on input
 *   - Backspace navigates to previous field
 *   - Full paste support (distributes characters across fields)
 *   - Disabled / readonly states
 *   - ARIA accessible
 *   - Callbacks: onChange, onComplete
 *   - Programmatic API: getControl() with value get/set/clear/focus
 *
 * HTML pattern:
 *   <div id="my-pin"></div>
 */
const PinInput = class {
    #el = null;
    #destroyed = false;
    #fields = [];
    #config = {};
    #stateRef = null;
    #setState = null;
    #length = 6;
    #sm = null;      // component-level StateMachine
    #eventAC = null; // AbortController for event cleanup
    #hiddenInput = null;

    /**
     * Creates a new PinInput instance.
     * @param {string|Element} selector - The container element or selector.
     * @param {Object} [config={}] - Configuration options.
     * @param {number} [config.length=6] - Number of digits.
     * @param {string} [config.type='numeric'] - 'numeric' or 'alphanumeric'.
     * @param {boolean} [config.masked=false] - Show dots instead of characters.
     * @param {boolean} [config.disabled=false] - Start disabled.
     * @param {string} [config.placeholder='○'] - Placeholder per cell.
     * @param {boolean} [config.autoFocus=false] - Focus first field on init.
     * @param {Function} [config.onChange] - Callback triggered on every change.
     * @param {Function} [config.onComplete] - Callback triggered when all filled.
     */
    constructor(selector, config = {}) {
        const el = razyui(selector);

        if (!el.length) {
            console.warn('PinInput: element not found \u2192', selector);
            return;
        }

        this.#el = el;
        this.#config = { ...DEFAULTS, ...config };
        this.#length = config.length ?? DEFAULTS.length;

        this.#init();
    }

    #init() {
        const el  = this.#el;
        const cfg = this.#config;
        const len = this.#length;

        // 1. View: build DOM (container + input fields)
        this.#fields = buildDOM(el, cfg, len);

        // 2. StateMachine (component-level)
        this.#sm = new StateMachine(DEF.states, { el, fields: this.#fields });

        if (cfg.disabled) {
            this.#sm.reset('disabled');
        }

        // 3. Reactive state — wired to field sync effect
        const { ref, setState } = createReactiveState(razyui.state, this.#fields);
        this.#stateRef = ref;
        this.#setState = setState;

        // 4. Events — centralised binding with AbortController cleanup
        // Capture `this` for the provider getters
        const self = this;
        const handlerCtx = createHandlerCtx({
            get fields()          { return self.#fields; },
            get length()          { return self.#length; },
            get config()          { return self.#config; },
            syncFromFields: ()    => self.#syncFromFields(),
        });

        this.#eventAC = bindEvents(this.#fields, handlerCtx, this.#sm);

        // 5. Auto-focus
        if (cfg.autoFocus) {
            requestAnimationFrame(() => this.#fields.focus());
        }

        // 6. Hidden input for native form submission
        if (cfg.name) {
            const hidden = document.createElement('input');
            hidden.type = 'hidden';
            hidden.name = cfg.name;
            hidden.value = '';
            el[0].appendChild(hidden);
            this.#hiddenInput = hidden;
        }
    }

    /** Read field values into state, fire callbacks. */
    #syncFromFields() {
        const val = this.#fields.map(f => f.value).join('');
        this.#setState({ value: val });
        if (this.#hiddenInput) this.#hiddenInput.value = val;

        emitEvent(this.#el[0], 'change', { value: val });
        if (typeof this.#config.onChange === 'function') {
            this.#config.onChange.call(this, val);
        }

        if (val.length === this.#length) {
            emitEvent(this.#el[0], 'complete', { value: val });
            if (typeof this.#config.onComplete === 'function') {
                this.#config.onComplete.call(this, val);
            }
        }
    }

    // ── Public API ──

    /** 
     * Get the current PIN value. 
     * @returns {string} The current PIN value.
     */
    get value() {
        return this.#stateRef.value;
    }

    /** 
     * Set the PIN value programmatically. 
     * @param {string} v - The value to set.
     */
    set value(v) {
        const str = String(v).slice(0, this.#length);
        this.#fields.forEach((f, i) => {
            f.value = str[i] || '';
            f.dataset.prev = f.value;
        });
        this.#syncFromFields();
    }

    /** 
     * Clear all fields. 
     */
    clear() {
        this.#fields.forEach(f => { f.value = ''; f.dataset.prev = ''; });
        this.#syncFromFields();
        this.#fields[0]?.focus();
    }

    /** 
     * Focus the first empty field (or the first field). 
     */
    focus() {
        const idx = this.#fields.findIndex(f => !f.value);
        (this.#fields[idx >= 0 ? idx : 0])?.focus();
    }

    blur() {
        const active = this.#fields.find(f => f === document.activeElement);
        if (active) active.blur();
    }

    /** 
     * Enable or disable. 
     * @param {boolean} v - True to disable, false to enable.
     */
    set disabled(v) {
        this.#config.disabled = !!v;
        if (v && this.#sm.can('DISABLE')) {
            this.#sm.send('DISABLE');
        } else if (!v && this.#sm.is('disabled')) {
            this.#sm.send('ENABLE');
        }
    }

    setInvalid(invalid) {
        this.#el.toggleClass(CLS.INVALID, !!invalid);
        this.#el[0][invalid ? 'setAttribute' : 'removeAttribute']('aria-invalid', 'true');
    }

    /**
     * Get disabled state.
     * @returns {boolean} True if disabled, false otherwise.
     */
    get disabled() {
        return this.#sm.is('disabled');
    }

    /** 
     * Toggle masked mode. 
     * @param {boolean} v - True to mask, false to unmask.
     */
    set masked(v) {
        this.#config.masked = !!v;
        const type = v ? 'password' : 'text';
        this.#fields.forEach(f => { f.type = type; });
    }

    /**
     * Get masked state.
     * @returns {boolean} True if masked, false otherwise.
     */
    get masked() {
        return !!this.#config.masked;
    }

    /**
     * Get a reactive control object.
     * @returns {Object} ctrl - The control object.
     */
    getControl() {
        const self = this;
        return {
            get value() { return self.value; },
            set value(v) { self.value = v; },
            get disabled() { return self.disabled; },
            set disabled(v) { self.disabled = v; },
            get masked() { return self.masked; },
            set masked(v) { self.masked = v; },
            get type() { return self.#config.type; },
            set type(v) {
                self.#config.type = v;
                const pattern = v === 'numeric' ? '[0-9]' : '[0-9a-zA-Z]';
                self.#fields.forEach(f => f.setAttribute('pattern', pattern));
            },
            get placeholder() { return self.#config.placeholder; },
            set placeholder(v) {
                self.#config.placeholder = v ?? '';
                self.#fields.forEach(f => { f.placeholder = v ?? ''; });
            },
            clear:             () => self.clear(),
            focus:             () => self.focus(),
            blur:              () => self.blur(),
            setInvalid:        (v) => self.setInvalid(v),
            destroy:           () => self.destroy(),
            checkValidity:     () => self.#hiddenInput ? self.#hiddenInput.checkValidity() : true,
            reportValidity:    () => self.#hiddenInput ? self.#hiddenInput.reportValidity() : true,
            setCustomValidity: (m) => { if (self.#hiddenInput) self.#hiddenInput.setCustomValidity(m || ''); self.setInvalid(!!m); },
            get label() { return self.#el[0].getAttribute('aria-label'); },
            set label(v) { v ? self.#el[0].setAttribute('aria-label', v) : self.#el[0].removeAttribute('aria-label'); },
            get labelledby() { return self.#el[0].getAttribute('aria-labelledby'); },
            set labelledby(v) { v ? self.#el[0].setAttribute('aria-labelledby', v) : self.#el[0].removeAttribute('aria-labelledby'); },
            get describedby() { return self.#el[0].getAttribute('aria-describedby'); },
            set describedby(v) { v ? self.#el[0].setAttribute('aria-describedby', v) : self.#el[0].removeAttribute('aria-describedby'); },
            get name() { return self.#config.name ?? ''; },
            set name(v) { self.#config.name = v; if (self.#hiddenInput) self.#hiddenInput.name = v; },
            get required() { return self.#config.required ?? false; },
            set required(v) { self.#config.required = !!v; if (self.#hiddenInput) self.#hiddenInput.required = !!v; self.#el[0].setAttribute('aria-required', String(!!v)); },
            get element() { return self.#el[0]; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /** Cleanup and restore original element. */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        if (this.#hiddenInput) { this.#hiddenInput.remove(); this.#hiddenInput = null; }
        cleanupDOM(this.#el);
        this.#fields = [];
    }
};

export default PinInput;
