/**
 * @fileoverview PinInput constants — CSS classes, ARIA attributes, defaults.
 * @module module/PinInput/constants
 */
import { defineParts } from '../shared/definePart.js';


/** CSS class names */
export const CLS = Object.freeze({
    ROOT:     'rz-pin-input',
    FIELD:    'rz-pin-field',
    disabled: 'is-disabled',
    FILLED:   'is-filled',
    FOCUSED:  'is-focused',
    INVALID:  'is-error',
});

/** ARIA attribute values */
export const ARIA = Object.freeze({
    ROLE:  'group',
    LABEL: 'PIN input',
});

/** Default configuration values */
export const DEFAULTS = Object.freeze({
    length:       6,
    type:         'numeric',
    placeholder:  '○',
    masked:       false,
    disabled:     false,
    autoFocus:   false,
    autocomplete: 'one-time-code',
});

/** Semantic part names for pre-render styling overrides. */
export const PART = defineParts('PinInput', {
    ROOT        : { class: 'rz-pin-input', aliases: ['root', 'container', 'pin-input'] },
    FIELD       : { class: 'rz-pin-field', tag: 'input', aliases: ['field', 'input'] },
});

PART.ROOT.jit     = 'inline-flex items-center gap-[var(--pi-gap)] {is-disabled}:[opacity:.45] {is-disabled}:pointer-events-none {is-shake}:motion-shake';
PART.FIELD.jit    = 'w-[var(--pi-field-width)] h-[var(--pi-field-height)] [line-height:var(--pi-field-height)] [border:var(--pi-border-width)_solid_var(--pi-border)] rounded-[var(--pi-radius)] bg-[var(--pi-bg)] fg-[var(--pi-text)] [font-family:var(--pi-font-mono)] text-[var(--pi-font-size)] fw-[var(--pi-font-weight)] text-center [outline:none] [caret-color:var(--pi-accent)] [padding:0] placeholder:fg-[var(--pi-text-muted)] placeholder:fw-400 hover:[border-color:var(--pi-border-strong)] {is-focused}:[border-color:var(--pi-accent)] {is-focused}:[box-shadow:0_0_0_3px_var(--pi-accent-subtle)] focus:[border-color:var(--pi-accent)] focus:[box-shadow:0_0_0_3px_var(--pi-accent-subtle)] {is-filled}:[border-color:var(--pi-border-strong)] {is-filled}:bg-[var(--pi-bg-raised)] disabled:bg-[var(--pi-bg-inset)] disabled:cursor-not-allowed ^{is-error}:[border-color:var(--pi-danger)] ^{is-success}:[border-color:var(--pi-success)]';