/**
 * @fileoverview PinInput events — centralised event binding via AbortController.
 * @module module/PinInput/events
 */

import razyui from '../../index.js';
import { PinInputDef as DEF } from '../PinInput.def.js';
import { DEFAULTS } from './constants.js';

/**
 * Create the handler context object consumed by DEF event dispatchers.
 * Uses a reference to live data so properties always reflect current state.
 *
 * @param {object} provider — { fields, length, config, syncFromFields }
 * @returns {object} handler context with live getters
 */
export function createHandlerCtx(provider) {
    return {
        get fields()    { return provider.fields; },
        get length()    { return provider.length; },
        get isNumeric() { return (provider.config.type ?? DEFAULTS.type) === 'numeric'; },
        syncFromFields: () => provider.syncFromFields(),
    };
}

/**
 * Bind input, keydown, focus, blur, and paste events on every field.
 * Returns an AbortController — call `.abort()` to unbind all listeners.
 *
 * @param {HTMLInputElement[]} fields — array of input elements
 * @param {object} ctx — handler context from createHandlerCtx
 * @param {object} sm — component-level StateMachine
 * @returns {AbortController}
 */
export function bindEvents(fields, ctx, sm) {
    const ac   = new AbortController();
    const opts = { signal: ac.signal };

    fields.forEach((field, i) => {
        const $field = razyui(field);

        $field.on('input', (e) => {
            DEF.handlers.field.input(ctx, e, i);
        }, opts);

        $field.on('keydown', (e) => {
            DEF.handlers.field.keydown(ctx, e, i);
        }, opts);

        $field.on('focus', (e) => {
            DEF.handlers.field.focus(ctx, e, i);
            if (sm.can('FOCUS')) sm.send('FOCUS');
        }, opts);

        $field.on('blur', (e) => {
            DEF.handlers.field.blur(ctx, e, i);
            // Check if any field still focused; if not, blur the SM
            requestAnimationFrame(() => {
                const anyFocused = fields.some(f => f === document.activeElement);
                if (!anyFocused && sm.can('BLUR')) sm.send('BLUR');
            });
        }, opts);

        $field.on('paste', (e) => {
            DEF.handlers.field.paste(ctx, e, i);
        }, opts);
    });

    return ac;
}
